  "inlineSchema": "// RadarBuds Database Schema\n// Cannabis strain rating application\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n}\n\nmodel User {\n  id        String   @id @default(cuid())\n  email     String   @unique\n  name      String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n  ratings   Rating[]\n}\n\nmodel Strain {\n  id         String   @id @default(cuid())\n  name       String   @unique // Strain name (e.g., \"Blue Dream\")\n  genetics   String // Parent strains or genetics info\n  strainType String // indica, sativa, hybrid variants\n  thcPercent Float? // THC percentage if known\n  cbdPercent Float? // CBD percentage if known\n  grower     String? // Cultivator/brand\n  origin     String? // State/region of origin\n  imageUrl   String? // URL to strain/bud image\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n  ratings    Rating[]\n\n  // Group session relations\n  sessionStrains  SessionStrain[]\n  currentSessions Session[]\n\n  @@index([name])\n  @@index([genetics])\n  @@index([strainType])\n}\n\nmodel Rating {\n  id String @id @default(cuid())\n\n  // Effect ratings stored as JSON (all 13 dimensions)\n  effectRatings Json\n\n  // Strain type at time of rating\n  strainType String\n\n  // Bud appearance (optional)\n  budAppearance String?\n\n  // Overall star rating (1-10)\n  overallRating Int\n\n  // Tasting notes\n  notes String?\n\n  // Selected effect tags (e.g., [\"Uplifting\", \"Creative\", \"Relaxing\"])\n  effectTags Json?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  user   User?   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  userId String? // Optional for anonymous ratings\n\n  strain   Strain @relation(fields: [strainId], references: [id], onDelete: Cascade)\n  strainId String\n\n  @@index([userId])\n  @@index([strainId])\n}\n\n// Analytics events for tracking user behavior\nmodel Event {\n  id String @id @default(cuid())\n\n  // Event type: search, view_strain, rate, compare, etc.\n  type String\n\n  // User identifier (could be anonymous session ID or user ID)\n  sessionId String\n  userId    String?\n\n  // Event-specific data as JSON\n  data Json\n\n  // Page/component where event occurred\n  source String?\n\n  // Device/browser info\n  userAgent String?\n\n  createdAt DateTime @default(now())\n\n  @@index([type])\n  @@index([sessionId])\n  @@index([userId])\n  @@index([createdAt])\n}\n\n// User taste profile (aggregated from their ratings)\nmodel TasteProfile {\n  id String @id @default(cuid())\n\n  userId String @unique\n\n  // Aggregated average effect profile across all ratings\n  avgProfile Json\n\n  // Number of ratings used to calculate profile\n  ratingCount Int\n\n  // Top effect tags selected across all ratings\n  topEffectTags Json?\n\n  // Preferred genetics (based on high ratings)\n  preferredGenetics Json?\n\n  // Preferred strain types\n  preferredTypes Json?\n\n  // Average overall rating given\n  avgOverallRating Float?\n\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n}\n\n// =============================================\n// Group Session Models\n// =============================================\n\n// A group session where multiple participants rate strains together\nmodel Session {\n  id       String  @id @default(cuid())\n  passcode String  @unique // 4-digit passcode for joining\n  name     String? // Optional session name (e.g., \"Friday Sesh\")\n\n  // Session state: waiting | rating | reviewing | ended\n  status String @default(\"waiting\")\n\n  // Host info\n  hostId   String\n  hostName String\n\n  // Current strain being rated (null when in waiting/reviewing)\n  currentStrainId String?\n  currentStrain   Strain? @relation(fields: [currentStrainId], references: [id])\n\n  // Screen sync mode - host controls what question participants see\n  screenSyncEnabled Boolean @default(false)\n\n  // Current rating phase for sync mode: \"type\" | \"appearance\" | \"effect-0\" to \"effect-12\" | \"overall\"\n  currentPhase String?\n\n  // Authenticated user who created this session (for profile linking)\n  userId String?\n\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n  endedAt   DateTime?\n\n  // Relations\n  participants   SessionParticipant[]\n  messages       SessionMessage[]\n  sessionStrains SessionStrain[]\n  sessionRatings SessionRating[]\n  userEvents     UserSessionEvent[]\n\n  @@index([passcode])\n  @@index([status])\n  @@index([hostId])\n  @@index([userId])\n}\n\n// Participant in a session\nmodel SessionParticipant {\n  id        String  @id @default(cuid())\n  sessionId String\n  session   Session @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n\n  // Participant identity (can be anonymous)\n  participantId String // Could be user ID or anonymous session ID\n  displayName   String\n  isHost        Boolean @default(false)\n\n  // Connection status\n  isOnline Boolean  @default(true)\n  lastSeen DateTime @default(now())\n\n  joinedAt DateTime @default(now())\n\n  @@unique([sessionId, participantId])\n  @@index([sessionId])\n  @@index([participantId])\n}\n\n// Chat messages in a session\nmodel SessionMessage {\n  id        String  @id @default(cuid())\n  sessionId String\n  session   Session @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n\n  senderId   String\n  senderName String\n  message    String\n\n  // Message type: chat | system (for join/leave notifications)\n  type String @default(\"chat\")\n\n  createdAt DateTime @default(now())\n\n  @@index([sessionId])\n  @@index([createdAt])\n}\n\n// Strains rated in a session (tracks order and reveal status)\nmodel SessionStrain {\n  id        String  @id @default(cuid())\n  sessionId String\n  session   Session @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n\n  strainId String\n  strain   Strain @relation(fields: [strainId], references: [id])\n\n  // Order in which strains were presented\n  orderIndex Int\n\n  // When results were revealed (null = still hidden/blind)\n  revealedAt DateTime?\n\n  createdAt DateTime @default(now())\n\n  @@unique([sessionId, strainId])\n  @@index([sessionId])\n}\n\n// Individual ratings within a session (separate from main Rating for blind tracking)\nmodel SessionRating {\n  id        String  @id @default(cuid())\n  sessionId String\n  session   Session @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n\n  sessionStrainId String // Links to SessionStrain\n  participantId   String // Who submitted\n  participantName String\n\n  // Rating data (matches main Rating structure)\n  effectRatings Json\n  strainType    String\n  budAppearance String?\n  overallRating Int\n  notes         String?\n  effectTags    Json?\n\n  submittedAt DateTime @default(now())\n\n  @@unique([sessionId, sessionStrainId, participantId])\n  @@index([sessionId])\n  @@index([participantId])\n}\n\n// User's participation in a session (for profile history)\nmodel UserSessionEvent {\n  id String @id @default(cuid())\n\n  // Authenticated user who participated\n  userId String\n\n  // Session reference\n  sessionId String\n  session   Session @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n\n  // Role in the session\n  wasHost Boolean @default(false)\n\n  // Display name used during the session\n  displayName String\n\n  // When user joined\n  joinedAt DateTime @default(now())\n\n  @@unique([userId, sessionId])\n  @@index([userId])\n  @@index([sessionId])\n}\n",
